UPDATE audit_control_answers SET audit_control_id = (SELECT k.id FROM audit_controls k INNER JOIN audit_controls l ON l.id = audit_control_answers.audit_control_id AND l.control_id IN (SELECT id FROM controls WHERE control_id IN ('KCF_SR-3b','KCF_SR-3c') AND framework = 'KROGER_CCF') INNER JOIN audit_controls kk ON kk.audit_id = l.audit_id AND kk.control_id = (SELECT id FROM controls WHERE control_id = 'KCF_SR-3a' AND framework = 'KROGER_CCF') WHERE k.id = kk.id) WHERE audit_control_id IN (SELECT id FROM controls WHERE control_id IN ('KCF_SR-3b','KCF_SR-3c') AND framework = 'KROGER_CCF') AND EXISTS (SELECT 1 FROM audit_controls k WHERE k.audit_id = (SELECT audit_id FROM audit_controls WHERE id = audit_control_answers.audit_control_id) AND k.control_id = (SELECT id FROM controls WHERE control_id = 'KCF_SR-3a' AND framework = 'KROGER_CCF'));
DELETE FROM audit_control_assignments WHERE audit_control_id IN (SELECT id FROM controls WHERE control_id IN ('KCF_SR-3b','KCF_SR-3c') AND framework = 'KROGER_CCF') AND EXISTS (SELECT 1 FROM audit_control_assignments x WHERE x.audit_control_id IN (SELECT id FROM audit_controls WHERE control_id = (SELECT id FROM controls WHERE control_id = 'KCF_SR-3a' AND framework = 'KROGER_CCF')) AND x.user_id = audit_control_assignments.user_id AND x.assignment_role = audit_control_assignments.assignment_role AND audit_control_assignments.audit_control_id IN (SELECT id FROM audit_controls WHERE control_id IN (SELECT id FROM controls WHERE control_id IN ('KCF_SR-3b','KCF_SR-3c') AND framework = 'KROGER_CCF')));
UPDATE audit_control_assignments SET audit_control_id = (SELECT k.id FROM audit_controls k JOIN audit_controls l ON l.id = audit_control_assignments.audit_control_id JOIN audit_controls kk ON kk.audit_id = l.audit_id AND kk.control_id = (SELECT id FROM controls WHERE control_id = 'KCF_SR-3a' AND framework = 'KROGER_CCF') WHERE k.id = kk.id) WHERE audit_control_id IN (SELECT id FROM controls WHERE control_id IN ('KCF_SR-3b','KCF_SR-3c') AND framework = 'KROGER_CCF') AND EXISTS (SELECT 1 FROM audit_controls k WHERE k.audit_id = (SELECT audit_id FROM audit_controls WHERE id = audit_control_assignments.audit_control_id) AND k.control_id = (SELECT id FROM controls WHERE control_id = 'KCF_SR-3a' AND framework = 'KROGER_CCF'));
UPDATE audit_evidences SET audit_control_id = (SELECT k.id FROM audit_controls k JOIN audit_controls l ON l.id = audit_evidences.audit_control_id JOIN audit_controls kk ON kk.audit_id = l.audit_id AND kk.control_id = (SELECT id FROM controls WHERE control_id = 'KCF_SR-3a' AND framework = 'KROGER_CCF') WHERE k.id = kk.id) WHERE audit_control_id IN (SELECT id FROM controls WHERE control_id IN ('KCF_SR-3b','KCF_SR-3c') AND framework = 'KROGER_CCF') AND EXISTS (SELECT 1 FROM audit_controls k WHERE k.audit_id = (SELECT audit_id FROM audit_controls WHERE id = audit_evidences.audit_control_id) AND k.control_id = (SELECT id FROM controls WHERE control_id = 'KCF_SR-3a' AND framework = 'KROGER_CCF'));
UPDATE findings SET audit_control_id = (SELECT k.id FROM audit_controls k JOIN audit_controls l ON l.id = findings.audit_control_id JOIN audit_controls kk ON kk.audit_id = l.audit_id AND kk.control_id = (SELECT id FROM controls WHERE control_id = 'KCF_SR-3a' AND framework = 'KROGER_CCF') WHERE k.id = kk.id) WHERE audit_control_id IN (SELECT id FROM controls WHERE control_id IN ('KCF_SR-3b','KCF_SR-3c') AND framework = 'KROGER_CCF') AND EXISTS (SELECT 1 FROM audit_controls k WHERE k.audit_id = (SELECT audit_id FROM audit_controls WHERE id = findings.audit_control_id) AND k.control_id = (SELECT id FROM controls WHERE control_id = 'KCF_SR-3a' AND framework = 'KROGER_CCF'));
UPDATE control_exceptions SET audit_control_id = (SELECT k.id FROM audit_controls k JOIN audit_controls l ON l.id = control_exceptions.audit_control_id JOIN audit_controls kk ON kk.audit_id = l.audit_id AND kk.control_id = (SELECT id FROM controls WHERE control_id = 'KCF_SR-3a' AND framework = 'KROGER_CCF') WHERE k.id = kk.id) WHERE audit_control_id IN (SELECT id FROM controls WHERE control_id IN ('KCF_SR-3b','KCF_SR-3c') AND framework = 'KROGER_CCF') AND EXISTS (SELECT 1 FROM audit_controls k WHERE k.audit_id = (SELECT audit_id FROM audit_controls WHERE id = control_exceptions.audit_control_id) AND k.control_id = (SELECT id FROM controls WHERE control_id = 'KCF_SR-3a' AND framework = 'KROGER_CCF'));
DELETE FROM audit_controls WHERE control_id IN (SELECT id FROM controls WHERE control_id IN ('KCF_SR-3b','KCF_SR-3c') AND framework = 'KROGER_CCF') AND EXISTS (SELECT 1 FROM audit_controls k WHERE k.audit_id = audit_controls.audit_id AND k.control_id = (SELECT id FROM controls WHERE control_id = 'KCF_SR-3a' AND framework = 'KROGER_CCF'));
UPDATE audit_controls SET control_id = (SELECT id FROM controls WHERE control_id = 'KCF_SR-3a' AND framework = 'KROGER_CCF') WHERE control_id IN (SELECT id FROM controls WHERE control_id IN ('KCF_SR-3b','KCF_SR-3c') AND framework = 'KROGER_CCF');
UPDATE controls SET control_id = 'KCF_SR-3', name = 'SR-3', description = (SELECT GROUP_CONCAT(description ORDER BY control_id SEPARATOR ' | ') FROM controls c WHERE c.control_id IN ('KCF_SR-3a','KCF_SR-3b','KCF_SR-3c') AND c.framework = 'KROGER_CCF') WHERE control_id = 'KCF_SR-3a' AND framework = 'KROGER_CCF';
DELETE FROM controls WHERE control_id IN ('KCF_SR-3a','KCF_SR-3b','KCF_SR-3c') AND framework = 'KROGER_CCF' AND control_id <> 'KCF_SR-3';
